(function(){var DATA={"evolution":{"rating":4.93,"count":15,"reviews":10,"url":"https://www.goodreads.com/book/show/241706371-evolution"},"on-vacation":{"rating":4.7,"count":10,"reviews":5,"url":"https://www.goodreads.com/book/show/205491584-on-vacation"},"the-dream":{"rating":5.0,"count":12,"reviews":1,"url":"https://www.goodreads.com/book/show/63213444-the-dream"}};function stars(rating){var pct=(rating/5)*100;return'<span class="gr-stars" aria-hidden="true">'
+'<span class="gr-stars-empty">&#9733;&#9733;&#9733;&#9733;&#9733;</span>'
+'<span class="gr-stars-fill" style="width:'+pct.toFixed(1)+'%">&#9733;&#9733;&#9733;&#9733;&#9733;</span>'
+'</span>';}
function render(){document.querySelectorAll('[data-book]').forEach(function(el){var slug=el.dataset.book;var d=DATA[slug];if(!d)return;var badge=document.createElement('a');badge.href=d.url;badge.target='_blank';badge.rel='noopener noreferrer';badge.className='gr-badge';badge.setAttribute('aria-label',d.rating+' out of 5 stars on Goodreads');badge.innerHTML=stars(d.rating)+'<span class="gr-score">'+d.rating.toFixed(2)+'</span>'+'<span class="gr-logo">Goodreads</span>';el.appendChild(badge);});}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',render);}else{render();}})();